import sys
import os
import json
import subprocess
import time
import requests
from typing import Dict, Any, Optional

def test_http_server(url: str, headers: Optional[Dict[str, str]] = None) -> Dict[str, Any]:
    """Test connectivity to an MCP HTTP server."""
    start_time = time.time()
    try:
        # MCP spec: listTools is a common GET/POST endpoint to test connectivity
        # We'll try POST to 'listTools' first as it's common in MCP implementations
        # or just GET the base URL if it's a discovery endpoint.
        # But per MCP spec, it should be a JSON-RPC 2.0 request.

        payload = {
            "jsonrpc": "2.0",
            "id": 1,
            "method": "listTools",
            "params": {}
        }

        response = requests.post(
            url,
            json=payload,
            headers=headers or {},
            timeout=10
        )

        duration = time.time() - start_time

        if response.status_code != 200:
            return {
                "status": "error",
                "message": f"HTTP {response.status_code}",
                "detail": response.text[:200],
                "duration": duration
            }

        data = response.json()
        if "error" in data:
            return {
                "status": "error",
                "message": f"MCP Error: {data['error'].get('message', 'Unknown error')}",
                "detail": json.dumps(data["error"]),
                "duration": duration
            }

        result = data.get("result", {})
        tools = result.get("tools", [])

        return {
            "status": "connected",
            "version": "unknown", # HTTP MCP doesn't always show version in listTools
            "tools_count": len(tools),
            "duration": duration
        }
    except Exception as e:
        return {
            "status": "error",
            "message": str(e),
            "duration": time.time() - start_time
        }

def test_stdio_server(command: str, args: list[str], env: Optional[Dict[str, str]] = None) -> Dict[str, Any]:
    """Test connectivity to an MCP stdio server."""
    start_time = time.time()
    process = None
    try:
        # Spawn the process
        full_env = os.environ.copy()
        if env:
            full_env.update(env)

        process = subprocess.Popen(
            [command] + args,
            stdin=subprocess.PIPE,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            env=full_env,
            text=True,
            bufsize=1
        )

        # MCP Initialize request
        init_request = {
            "jsonrpc": "2.0",
            "id": 1,
            "method": "initialize",
            "params": {
                "protocolVersion": "2024-11-05",
                "capabilities": {},
                "clientInfo": {
                    "name": "ostwin-tester",
                    "version": "0.1.0"
                }
            }
        }

        # Send initialize request
        process.stdin.write(json.dumps(init_request) + "\n")
        process.stdin.flush()

        # Read response (with timeout)
        import select

        # Wait up to 5 seconds for stdout
        ready, _, _ = select.select([process.stdout], [], [], 5)

        if not ready:
            # Check if process died
            if process.poll() is not None:
                stderr = process.stderr.read()
                return {
                    "status": "error",
                    "message": "Process exited unexpectedly",
                    "detail": stderr[:200],
                    "duration": time.time() - start_time
                }
            return {
                "status": "error",
                "message": "Timeout waiting for response",
                "duration": time.time() - start_time
            }

        response_line = process.stdout.readline()
        if not response_line:
            return {
                "status": "error",
                "message": "Empty response from server",
                "duration": time.time() - start_time
            }

        data = json.loads(response_line)
        if "error" in data:
            return {
                "status": "error",
                "message": f"MCP Error: {data['error'].get('message', 'Unknown error')}",
                "detail": json.dumps(data["error"]),
                "duration": time.time() - start_time
            }

        result = data.get("result", {})
        server_info = result.get("serverInfo", {})

        # Now list tools
        list_tools_request = {
            "jsonrpc": "2.0",
            "id": 2,
            "method": "listTools",
            "params": {}
        }
        process.stdin.write(json.dumps(list_tools_request) + "\n")
        process.stdin.flush()

        ready, _, _ = select.select([process.stdout], [], [], 5)
        if ready:
            response_line = process.stdout.readline()
            data = json.loads(response_line)
            tools = data.get("result", {}).get("tools", [])
            tools_count = len(tools)
        else:
            tools_count = 0

        return {
            "status": "connected",
            "name": server_info.get("name", "unknown"),
            "version": server_info.get("version", "unknown"),
            "tools_count": tools_count,
            "duration": time.time() - start_time
        }

    except Exception as e:
        return {
            "status": "error",
            "message": str(e),
            "duration": time.time() - start_time
        }
    finally:
        if process:
            process.terminate()
            try:
                process.wait(timeout=1)
            except subprocess.TimeoutExpired:
                process.kill()

if __name__ == "__main__":
    # Simple CLI for the module itself to test it
    if len(sys.argv) < 2:
        print(json.dumps({"status": "error", "message": "Missing arguments"}))
        sys.exit(1)

    cmd_type = sys.argv[1]
    if cmd_type == "http":
        url = sys.argv[2]
        headers = json.loads(sys.argv[3]) if len(sys.argv) > 3 else {}
        print(json.dumps(test_http_server(url, headers)))
    elif cmd_type == "stdio":
        command = sys.argv[2]
        args = sys.argv[3:]
        print(json.dumps(test_stdio_server(command, args)))
    else:
        print(json.dumps({"status": "error", "message": f"Unknown type: {cmd_type}"}))

import json
import re
import os
import sys
from typing import Any, Dict, List, Tuple
from pathlib import Path

# Try to import vault from the same directory
try:
    from .vault import get_vault
except ImportError:
    # Fallback for standalone execution
    sys.path.append(os.path.dirname(os.path.abspath(__file__)))
    from vault import get_vault

# Regex to match ${vault:server/key}
VAULT_REF_PATTERN = re.compile(r"\$\{vault:([^/]+)/([^}]+)\}")

class ConfigResolver:
    def __init__(self):
        self.vault = get_vault()

    def resolve_config(self, config_dict: Dict[str, Any]) -> Dict[str, Any]:
        """Recursively resolves vault references in a config dictionary."""
        return self._resolve_recursive(config_dict)

    def _resolve_recursive(self, obj: Any) -> Any:
        if isinstance(obj, dict):
            return {k: self._resolve_recursive(v) for k, v in obj.items()}
        elif isinstance(obj, list):
            return [self._resolve_recursive(v) for v in obj]
        elif isinstance(obj, str):
            match = VAULT_REF_PATTERN.search(obj)
            if match:
                server, key = match.groups()
                secret = self.vault.get(server, key)
                if secret is None:
                    raise ValueError(f"Vault reference not found: ${{vault:{server}/{key}}}")
                # Replace the entire reference with the secret
                # Note: this only supports one reference per string for now
                return obj.replace(match.group(0), secret)
        return obj

    def has_unresolved_refs(self, config_dict: Dict[str, Any]) -> List[str]:
        """Returns a list of missing vault references as 'server/key' strings."""
        unresolved = []
        refs = self.extract_vault_refs(config_dict)
        for server, key in refs:
            if self.vault.get(server, key) is None:
                unresolved.append(f"{server}/{key}")
        return unresolved

    def extract_vault_refs(self, config_dict: Dict[str, Any]) -> List[Tuple[str, str]]:
        """Extracts all vault references found in the config dictionary."""
        refs = []
        self._extract_recursive(config_dict, refs)
        return sorted(list(set(refs)))

    def _extract_recursive(self, obj: Any, refs: List[Tuple[str, str]]):
        if isinstance(obj, dict):
            for v in obj.values():
                self._extract_recursive(v, refs)
        elif isinstance(obj, list):
            for v in obj:
                self._extract_recursive(v, refs)
        elif isinstance(obj, str):
            for match in VAULT_REF_PATTERN.finditer(obj):
                refs.append(match.groups())

    def compile_config(self, home_config: Dict[str, Any], builtin_config: Dict[str, Any]) -> Tuple[Dict[str, Any], Dict[str, str]]:
        """
        Compiles home config + builtin config into project config.
        Replaces ${vault:server/key} with ${ENV_VAR} and returns the env var mapping.
        """
        # Merge configs
        compiled_config = {"mcpServers": {}}
        compiled_config["mcpServers"].update(builtin_config.get("mcpServers", {}))
        compiled_config["mcpServers"].update(home_config.get("mcpServers", {}))

        env_vars = {}

        def _compile_recursive(obj, server_name):
            if isinstance(obj, dict):
                return {k: _compile_recursive(v, server_name) for k, v in obj.items()}
            elif isinstance(obj, list):
                return [_compile_recursive(v, server_name) for v in obj]
            elif isinstance(obj, str):
                match = VAULT_REF_PATTERN.search(obj)
                if match:
                    server, key = match.groups()
                    secret = self.vault.get(server, key)
                    if secret is None:
                        # If we can't find it in vault, we'll leave it as is for now
                        # or raise an error? The spec says to resolve it.
                        pass

                    # ENV var naming convention: MCP_{SERVER}_{KEY} (uppercased, sanitized)
                    env_name = f"MCP_{server.upper()}_{key.upper()}".replace("-", "_").replace(".", "_")
                    env_vars[env_name] = secret or ""
                    return obj.replace(match.group(0), f"${{{env_name}}}")
            return obj

        for name, server_cfg in compiled_config["mcpServers"].items():
            compiled_config["mcpServers"][name] = _compile_recursive(server_cfg, name)

        return compiled_config, env_vars

if __name__ == "__main__":
    # Test script
    resolver = ConfigResolver()
    test_config = {
        "mcpServers": {
            "test": {
                "env": {
                    "API_KEY": "${vault:test/API_KEY}",
                    "OTHER": "plain"
                }
            }
        }
    }
    print("Extracting refs:", resolver.extract_vault_refs(test_config))
    print("Has unresolved:", resolver.has_unresolved_refs(test_config))

    # Try setting a value and resolving
    resolver.vault.set("test", "API_KEY", "secret-value")
    print("Resolved config:", resolver.resolve_config(test_config))
    resolver.vault.delete("test", "API_KEY")

import { Entity, Column, PrimaryGeneratedColumn, CreateDateColumn, UpdateDateColumn, OneToMany } from "typeorm";
import { Video } from "./video.entity";

@Entity("users")
export class User {
  @PrimaryGeneratedColumn("uuid")
  id: string;

  @Column({ unique: true })
  username: string;

  @Column({ unique: true })
  email: string;

  @Column()
  password_hash: string;

  @OneToMany(() => Video, video => video.user)
  videos: Video[];
}

import { Entity, Column, PrimaryGeneratedColumn, CreateDateColumn, UpdateDateColumn, ManyToOne, JoinColumn } from "typeorm";
import { User } from "./user.entity";

export enum VideoStatus {
  PENDING = "pending",
  PROCESSING = "processing",
  COMPLETED = "completed",
  FAILED = "failed",
}

@Entity("videos")
export class Video {
  @PrimaryGeneratedColumn("uuid")
  id: string;

  @Column()
  user_id: string;

  @ManyToOne(() => User, user => user.videos, { onDelete: "CASCADE" })
  @JoinColumn({ name: "user_id" })
  user: User;

  @Column()
  title: string;

  @Column({ type: "enum", enum: VideoStatus, default: VideoStatus.PENDING })
  status: VideoStatus;
}

